// Validate x-api-key header for jobs endpoint
const headers = $input.item.json.headers;
const query = $input.item.json.query;
const apiKey = headers['x-api-key'];
const expectedKey = $env.ESTIMATOR_API_KEY;

if (!apiKey || apiKey !== expectedKey) {
  throw new Error('UNAUTHORIZED');
}

const customerId = query?.customerId;
if (!customerId) {
  throw new Error('customerId query parameter is required');
}

return { json: { authorized: true, customerId } };

