// Transform JT customers response for dropdown
const response = $input.item.json;

if (response.errors && response.errors.length > 0) {
  throw new Error(`JT API error: ${response.errors[0].message}`);
}

const edges = response.data?.accounts?.edges || [];

const customers = edges.map(edge => {
  const node = edge.node;
  const primaryLocation = node.locations?.find(l => l.id === node.primaryLocationId) || node.locations?.[0];
  const address = primaryLocation?.address;

  return {
    id: node.id,
    name: node.name,
    primaryLocationId: node.primaryLocationId,
    address: address ? `${address.street1}, ${address.city}, ${address.state} ${address.zip}` : null,
    locations: node.locations?.map(l => ({
      id: l.id,
      address: l.address ? `${l.address.street1}, ${l.address.city}, ${l.address.state} ${l.address.zip}` : null
    })) || []
  };
}).sort((a, b) => a.name.localeCompare(b.name));

return { json: { customers, count: customers.length } };

// Transform JT jobs response and filter by Phase
const response = $input.item.json;
const customerId = $('Validate Auth (Jobs)').item.json.customerId;

// Phase custom field ID - phases 1-3 are estimating stages
const PHASE_FIELD_ID = '22P4fguBu3Ub';
const ESTIMATING_PHASES = ['1', '2', '3'];

if (response.errors && response.errors.length > 0) {
  throw new Error(`JT API error: ${response.errors[0].message}`);
}

const edges = response.data?.jobs?.edges || [];

const jobs = edges
  .map(edge => {
    const node = edge.node;
    const phaseField = node.customFields?.find(cf => cf.customFieldId === PHASE_FIELD_ID);
    const phase = phaseField?.value || null;

    return {
      id: node.id,
      number: node.number,
      name: node.name,
      status: node.status,
      phase: phase,
      displayName: `#${node.number} - ${node.name}`
    };
  })
  // Filter to only estimating phases (1-3) or jobs without phase set
  .filter(job => !job.phase || ESTIMATING_PHASES.includes(job.phase))
  // Sort by job number descending (newest first)
  .sort((a, b) => parseInt(b.number) - parseInt(a.number));

return { json: { jobs, count: jobs.length, customerId } };
